-- Ken's Hardened V2 Fix

local b64_0xlIlIII = {}
local char_0x11I1lI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllIllI=1,#char_0x11I1lI do b64_0xlIlIII[char_0x11I1lI:sub(i_0xllIllI,i_0xllIllI)] = i_0xllIllI - 1 end

function b64_0xlIlIII.dec_0xlIlll1(d_0xI1llI1)
    d_0xI1llI1 = string.gsub(d_0xI1llI1, '[^'..char_0x11I1lI..'=]', '')
    local r_0x1I1lI1 = {}
    for i_0xllIllI=1, #d_0xI1llI1, 4 do
        local c_0xIlIIll = b64_0xlIlIII[d_0xI1llI1:sub(i_0xllIllI,i_0xllIllI)] or 0
        local c_0xIIlIII = b64_0xlIlIII[d_0xI1llI1:sub(i_0xllIllI+1,i_0xllIllI+1)] or 0
        local c_0xlIlIII, c_0x1l111I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xI1llI1:sub(i_0xllIllI+2,i_0xllIllI+2)
        if ch3 == "=" then has3 = false else c_0xlIlIII = b64_0xlIlIII[ch3] or 0 end
        local ch4 = d_0xI1llI1:sub(i_0xllIllI+3,i_0xllIllI+3)
        if ch4 == "=" then has4 = false else c_0x1l111I = b64_0xlIlIII[ch4] or 0 end
        local b_0xlI1III = c_0xIlIIll * (2^18) + c_0xIIlIII * (2^12) + c_0xlIlIII * (2^6) + c_0x1l111I
        local b_0xII11I1 = math.floor(b_0xlI1III / (2^16)) % (2^8)
        local b_0x11I1ll = math.floor(b_0xlI1III / (2^8)) % (2^8)
        local b_0x1Il1II = b_0xlI1III % (2^8)
        table.insert(r_0x1I1lI1, string.char(b_0xII11I1))
        if has3 then table.insert(r_0x1I1lI1, string.char(b_0x11I1ll)) end
        if has4 then table.insert(r_0x1I1lI1, string.char(b_0x1Il1II)) end
    end
    return table.concat(r_0x1I1lI1)
end


local function bxor_0xlIIII1(a_0xIIllIl,b_0xIIIIll)
    if bit32 then return bit32.bxor(a_0xIIllIl,b_0xIIIIll) end
    local r_0xIIIllI = 0
    for i_0xllllII = 0, 7 do
        local x_0xlIlIII = a_0xIIllIl % 2
        local y_0x1IlIll = b_0xIIIIll % 2
        if x_0xlIlIII ~= y_0x1IlIll then r_0xIIIllI = r_0xIIIllI + (2^i_0xllllII) end
        a_0xIIllIl = math.floor(a_0xIIllIl / 2)
        b_0xIIIIll = math.floor(b_0xIIIIll / 2)
    end
    return r_0xIIIllI
end


local function bxor_str_0xII1l1I(s_0xllIIl1, k_0xllI1II)
    local r_0x1IIIII = {}
    for i_0xI1lIII=1, #s_0xllIIl1 do
        local b_0xl1lIlI = string.byte(s_0xllIIl1, i_0xI1lIII)
        local kb_0xII11Il = string.byte(k_0xllI1II, (i_0xI1lIII-1) % #k_0xllI1II + 1)
        r_0x1IIIII[i_0xI1lIII] = string.char(bxor_0xlIIII1(b_0xl1lIlI, kb_0xII11Il))
    end
    return table.concat(r_0x1IIIII)
end


local function getkeys_0xIlllII()
    local seed = b64_0xlIlIII.dec_0xlIlll1("NWJwU2NPcWM=")
    local k1_enc = b64_0xlIlIII.dec_0xlIlll1("TzICJwIZGDk=")
    local k2_enc = b64_0xlIlIII.dec_0xlIlll1("ZjcFNzR7KQ0=")
    return bxor_str_0xII1l1I(k1_enc, seed), bxor_str_0xII1l1I(k2_enc, seed)
end


local function cff_0xIIlIIl(a_0xI11lll)
    local st_0xI1l1Il = 0
    local res_0xIIl1ll = a_0xI11lll
    while true do
        if st_0xI1l1Il == 0 then
            res_0xIIl1ll = res_0xIIl1ll + 1
            st_0xI1l1Il = 1
        elseif st_0xI1l1Il == 1 then
            res_0xIIl1ll = res_0xIIl1ll * 2
            st_0xI1l1Il = 2
        elseif st_0xI1l1Il == 2 then
            res_0xIIl1ll = res_0xIIl1ll - 3
            st_0xI1l1Il = 3
        else
            break
        end
    end
    return res_0xIIl1ll
end


local function chain_0x1IIIII(x) return x*2 end
local function chain_0xIl1lIl(x) return chain_0x1IIIII(x)+1 end


local d_0xl1IIIl = {
  {op=255, val="", is_enc=true},
}
local pc_0xIlIlII = 1
local stk_0xI1IllI = {}
stk_0xI1IllI._jmp = nil


local disp_0x1lIlIl = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIlllII()

local state_0xllllI1 = 0
while true do
    if state_0xllllI1 == 0 then  -- FETCH
        if pc_0xIlIlII > #d_0xl1IIIl then break end
        local inst = d_0xl1IIIl[pc_0xIlIlII]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIlIII.dec_0xlIlll1(val)
            d = bxor_str_0xII1l1I(d, k2)
            val = bxor_str_0xII1l1I(d, k1)
        end
        stk_0xI1IllI._jmp = nil
        pc_0xIlIlII = pc_0xIlIlII + 1
        cur_op_0x1IllIl = opcode
        cur_val_0xllIlIl = val
        state_0xllllI1 = 1

    elseif state_0xllllI1 == 1 then  -- EXECUTE
        local handler = disp_0x1lIlIl[cur_op_0x1IllIl]
        if handler then
            handler(stk_0xI1IllI, cur_val_0xllIlIl)
        end
        if stk_0xI1IllI._jmp then
            pc_0xIlIlII = pc_0xIlIlII + stk_0xI1IllI._jmp
        end
        state_0xllllI1 = 0
    else
        break
    end
end
